/*
================================================================================
  ChtotibDocPrint — установка БД с демо-данными (SQL Server 2019+, SSMS 18–20)
================================================================================
  1. Подключитесь к своему экземпляру SQL Server.
  2. Выполните весь скрипт (F5).
  3. Существующая база ChtotibDocPrint будет удалена и создана заново.

  Пример строки подключения:
    Server=.\SQLEXPRESS;Database=ChtotibDocPrint;Trusted_Connection=True;TrustServerCertificate=True;
================================================================================
*/
SET NOCOUNT ON;
SET ANSI_NULLS ON;
SET QUOTED_IDENTIFIER ON;
SET ANSI_PADDING ON;
SET ANSI_WARNINGS ON;
SET ARITHABORT ON;
SET CONCAT_NULL_YIELDS_NULL ON;
SET NUMERIC_ROUNDABORT OFF;
GO

USE master;
GO

IF DB_ID(N'ChtotibDocPrint') IS NOT NULL
BEGIN
    PRINT N'Удаление базы ChtotibDocPrint...';
    ALTER DATABASE [ChtotibDocPrint] SET SINGLE_USER WITH ROLLBACK IMMEDIATE;
    DROP DATABASE [ChtotibDocPrint];
END
GO

PRINT N'Создание базы ChtotibDocPrint...';
CREATE DATABASE [ChtotibDocPrint];
GO

DECLARE @ver INT = CAST(SERVERPROPERTY('ProductMajorVersion') AS INT);
DECLARE @compat TINYINT = CASE
    WHEN @ver >= 16 THEN 160
    WHEN @ver >= 15 THEN 150
    WHEN @ver >= 14 THEN 140
    ELSE 130 END;
DECLARE @compatSql NVARCHAR(200) = N'ALTER DATABASE [ChtotibDocPrint] SET COMPATIBILITY_LEVEL = ' + CAST(@compat AS NVARCHAR(10));
EXEC sp_executesql @compatSql;
GO

USE [ChtotibDocPrint];
GO
CREATE TABLE [dbo].[Groups](
	[Id] [int] IDENTITY(1,1) NOT NULL,
	[SpecialtyId] [int] NOT NULL,
	[Name] [nvarchar](50) NOT NULL,
	[EnrollmentYear] [int] NOT NULL,
	[Address] [nvarchar](200) NULL,
	[IsGraduating] [bit] NOT NULL,
	[CourseNumber] [int] NOT NULL,
	[CreatedAt] [datetime2](7) NOT NULL,
PRIMARY KEY CLUSTERED 
(
	[Id] ASC
)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]
) ON [PRIMARY]
