-- VIEW: выпускники без рег. номера (для уведомления)
CREATE VIEW [dbo].[vw_GraduatesWithoutRegNumber] AS
SELECT s.Id, s.LastName, s.FirstName, s.MiddleName, g.Name AS GroupName
FROM dbo.Students s
INNER JOIN dbo.Groups g ON s.GroupId = g.Id
WHERE g.IsGraduating = 1
  AND s.IsExpelled = 0
  AND (s.RegistrationNumber IS NULL OR s.RegistrationNumber = N'');

GO

